import Splide from '@splidejs/splide';

const productSliders = document.querySelectorAll(".products-section__row");

const productSlidersSettings = {
  arrows: true,
  rewind: false,
  autoplay: false,
  perPage: 4,
  width: '100%',
  perMove: 4,
  gap: '2em',
  pagination: true,
  breakpoints: {
    1200: {
      perPage: 3,
      perMove: 3,
    },
    992: {
      perPage: 2,
      perMove: 2,
      gap: '1em',
    },
    576: {
      perPage: 1,
      perMove: 1,
    },
  }
};

productSliders.forEach((slider) => {
  new Splide(slider, productSlidersSettings).mount();
});
