const amountElmCalc = () => {
  const amountElm = document.querySelector(".product-detail-intro-section__input");
  if (amountElm) {


    const amountPlusElm = document.querySelector(".product-detail-intro-section__btn-plus");
    const amountMinusElm = document.querySelector(".product-detail-intro-section__btn-minus");

    amountPlusElm.addEventListener('click', () => {
      amountElm.value = Number(amountElm.value) + 1;
    });

    amountMinusElm.addEventListener('click', () => {
      amountElm.value = Number(amountElm.value) - 1;
      if (Number(amountElm.value) < 1) {
        amountElm.value = 1
      }
    });
  }
};

amountElmCalc();
