import Headroom from "headroom.js";

function headrommInit() {
  const headerMainTopHeight = document.querySelector(".header-main__top").offsetHeight;
  // select your header or whatever element you wish
  const header = document.querySelector(".header-main");
  if (!header) {
    return
  }
  let options = {

    // vertical offset in px before element is first unpinned
    offset: headerMainTopHeight,
  };

  const headroom = new Headroom(header, options);
  headroom.init();
}

//Client width

const clientWidth = () => {
  document.documentElement.style.setProperty('--client-width', (document.body.clientWidth) + "px")
}
//Resize

window.addEventListener("resize", function () {
  headrommInit();
  clientWidth();
  if (window.matchMedia("(min-width: 62em)").matches) {
    const navMain = document.querySelector(".nav-main");
    if (navMain.classList.contains("js-transition")) {
      navMain.classList.remove("js-transition")
      headerNavHide();
      headerMaskHide();
    }
  }
  if (window.matchMedia("(min-width: 36em)").matches) {
    const headerSearchInner = document.querySelector(".__inner");
    if (!headerSearchInner) {
      return
    }
    if (headerSearchInner.classList.contains("js-search-open")) {

      headerSearchClose();
      headerMaskHide();
    }
  }
});

//Header nav

function headerNavButtonClick() {
  const navMain = document.querySelector(".nav-main");
  const headerNavButton = document.querySelector(".header-main__nav-button");

  headerNavButton.addEventListener("click", function () {
    if (!navMain.classList.contains("js-open")) {
      headerNavShow();
      headerMaskShow();

    } else {
      headerNavHide();
      headerMaskHide();
    }
    if (!navMain.classList.contains("js-transition")) {
      navMain.classList.add("js-transition")
    }
  });
}

function headerNavShow() {
  const navMain = document.querySelector(".nav-main");
  const headerNavButton = document.querySelector(".header-main__nav-button");
  const body = document.querySelector("body");
  const html = document.querySelector("html");

  navMain.classList.add("js-open")
  headerNavButton.classList.add("js-open")
  body.classList.add("js-no-scroll")
  html.classList.add("js-no-scroll")
}

function headerNavHide() {
  const navMain = document.querySelector(".nav-main");
  const headerNavButton = document.querySelector(".header-main__nav-button");
  const body = document.querySelector("body");
  const html = document.querySelector("html");

  navMain.classList.remove("js-open")
  headerNavButton.classList.remove("js-open")
  body.classList.remove("js-no-scroll")
  html.classList.remove("js-no-scroll")

  //Sub menu close
  const subMenuButtons = document.querySelectorAll(".sub-menu-button");
  if (subMenuButtons) {

    subMenuButtons.forEach(button => {
      if (button.classList.contains("js-open")) {
        button.classList.remove("js-open");
      }
      button.parentNode.classList.remove("js-open")
      if (button.parentNode.classList.contains("js-open")) {
        button.parentNode.querySelector(".sub-menu").classList.remove("js-open");
      }

    });
  }
  if (navMain.querySelector(".sub-menu")) {
    navMain.querySelector(".sub-menu").classList.remove("js-open");
  }

}

//Header Mask
function headerMaskClick() {
  const headerMask = document.querySelector(".header-mask");
  headerMask.addEventListener("click", function () {
    headerNavHide();
    headerMaskHide();
  });
}

function headerMaskShow() {
  const headerMask = document.querySelector(".header-mask");
  headerMask.classList.add("js-active");
}

function headerMaskHide() {
  const headerMask = document.querySelector(".header-mask");
  headerMask.classList.remove("js-active");
}


//Desktop submenu
function desktopSubmenu() {
  if (window.matchMedia("(min-width: 62em)").matches) {
    const subMenuItemHasChildren = document.querySelectorAll(".sub-menu .menu-item-has-children")

    for (let i = 0; i < subMenuItemHasChildren.length; i++) {
      subMenuItemHasChildren[i].addEventListener("mouseover", function () {
        let subSubMenu = subMenuItemHasChildren[i].querySelector(".sub-menu")
        let leftOffset = subSubMenu.getBoundingClientRect().left;
        let elWidht = subSubMenu.offsetWidth;

        if (window.innerWidth <= leftOffset + elWidht + 5) {
          subSubMenu.classList.add("js-sub-menu-left");
        }
      });
    }
  }
}

//Mobile submenu init
function mobileSubmenuInit() {
  const menuItemHasChildren = document.querySelectorAll(".menu-item-has-children")
  menuItemHasChildren.forEach(item => {
    item.insertAdjacentHTML('beforeend', '<span class="sub-menu-button"></span>');
  });
}

//Mobile submenu
function mobileSubmenu() {
  const subMenuButtons = document.querySelectorAll(".sub-menu-button");
  subMenuButtons.forEach(button => {
    button.addEventListener("click", function () {
      let item = button
      if (!item.classList.contains("js-open")) {
        item.classList.add("js-open");
        item.parentNode.classList.add("js-open");
        item.parentNode.querySelector(".sub-menu").classList.add("js-open");

      } else {
        item.classList.remove("js-open");
        item.parentNode.classList.remove("js-open");
        item.parentNode.querySelector(".sub-menu").classList.remove("js-open");


        if (item.parentNode.querySelector(".sub-menu .sub-menu")) {
          item.parentNode.querySelector(".sub-menu .sub-menu").classList.remove("js-open");
        }
      }
    });
  });
}
//Header lang
function headerLang() {

  const langCurrent = document.querySelector(".header-language-switcher__current");
  if (!langCurrent) {
    return
  }
  const langList = document.querySelector(".header-language-switcher__list");
  const otherElements = document.querySelector(".header-language-switcher *");

  langCurrent.addEventListener("click", function () {
    langList.classList.toggle("js-open");
  });

  //Close
  document.addEventListener("click", function (e) {
    if (otherElements !== e.target && langList !== e.target && langList.classList.contains("js-open")) {
      langList.classList.remove("js-open");
    }
  });

}
//Header search
function headerSearch() {
  const headerSearchBtn = document.querySelector(".header-search__button");
  if (!headerSearchBtn) {
    return
  }
  const headerSearchInner = document.querySelector(".header-search__inner");


  headerSearchBtn.addEventListener("click", function () {
    if (!headerSearchInner.classList.contains("js-search-open")) {
      headerSearchOpen();
    } else {
      headerSearchClose();
      headerMaskHide();
    }

  });

  //Close
  document.addEventListener("click", function (e) {
    if (!headerSearchInner.contains(e.target) && !headerSearchBtn.contains(e.target)) {
      if (headerSearchInner.classList.contains("js-search-open")) {
        headerSearchClose();
        headerMaskHide();
      }
    }
  })
}

function headerSearchOpen() {
  const headerSearchInner = document.querySelector(".header-search__inner");
  const headerSearchInput = document.querySelector(".header-search__input");
  const body = document.querySelector("body");
  const html = document.querySelector("html");

  headerSearchInner.classList.add("js-search-open");
  headerSearchInput.focus();

  if (window.matchMedia("(max-width: 35.938em)").matches) {
    headerMaskShow();
    body.classList.add("js-no-scroll")
    html.classList.add("js-no-scroll")
  }
}

function headerSearchClose() {
  const headerSearchInner = document.querySelector(".header-search__inner");
  const headerSearchInput = document.querySelector(".header-search__input");
  const body = document.querySelector("body");
  const html = document.querySelector("html");

  headerSearchInner.classList.remove("js-search-open");

  headerSearchInput.value = '';
  body.classList.remove("js-no-scroll")
  html.classList.remove("js-no-scroll")
}




headrommInit();
headerNavButtonClick();
headerMaskClick();
desktopSubmenu();
mobileSubmenuInit();
mobileSubmenu();
headerSearch();
headerLang();
clientWidth();
