import Swiper, {
  Navigation,
  Pagination,
  Autoplay,
  EffectFade
} from 'swiper';

Swiper.use([Navigation, Pagination, Autoplay, EffectFade]);


document.addEventListener("DOMContentLoaded", () => {
  //Up to phone landscape - up to 768px
  if (window.matchMedia("(min-width: 48em)").matches) {

    const timelineSlides = document.querySelectorAll(".main-intro-section__img");

    if (timelineSlides.length > 1) {
      const timeline = document.querySelectorAll(".main-intro-section__row");

      timeline.forEach(slider => {

        const swiperSettings = {
          slidesPerView: 1,
          spaceBetween: 0,
          centeredSlides: true,
          effect: 'fade',
          fadeEffect: {
            crossFade: true
          },
          speed: 3000,
          autoplay: {
            delay: 500,
            disableOnInteraction: false,
          },
          direction: 'horizontal',
        };

        new Swiper(slider, swiperSettings);
      });
    }
  }
});
