const openFastPopup = () => {

  const button = document.querySelector(".contact-widget .btn");
  if (!button) {
    return
  }

  button.addEventListener('click', () => {
    const popup = document.querySelector(".popup-form.fast-contact-form")
    popup.classList.add("--visible")
  });

}

const closeFastPopup = () => {
  document.addEventListener('click', (e) => {
    const target = e.target;
    const cross = document.querySelector(".fast-contact-form .popup-form__cross")
    const popup = document.querySelector(".popup-form.fast-contact-form")
    if (target === cross || target === popup) {
      if (popup.classList.contains("--visible")) {
        popup.classList.remove("--visible")
      }
    }
  });
}

openFastPopup();
closeFastPopup();
