import Splide from '@splidejs/splide';

const teamSliders = document.querySelectorAll(".team-slider-section__row");

const teamSlidersSettings = {
  arrows: true,
  rewind: false,
  autoplay: false,
  perPage: 4,
  width: '100%',
  perMove: 4,
  gap: '2em',
  pagination: true,
  breakpoints: {
    992: {
      perPage: 3,
      perMove: 3,
    },
    768: {
      perPage: 2,
      perMove: 2,
    },
    576: {
      perPage: 1,
      perMove: 1,
    }
  }

};

teamSliders.forEach((slider) => {
  new Splide(slider, teamSlidersSettings).mount();
});
