import Splide from '@splidejs/splide';

const productDetailSliders = document.querySelectorAll(".product-slider-section__row");

const productDetailSlidersSettings = {
  arrows: true,
  rewind: false,
  autoplay: false,
  perPage: 3,
  width: '100%',
  perMove: 3,
  gap: '2em',
  pagination: true,
  breakpoints: {
    992: {
      perPage: 2,
      perMove: 2,
      gap: '1em',
    },
    576: {
      perPage: 1,
      perMove: 1,
    },
  }
};

productDetailSliders.forEach((slider) => {
  new Splide(slider, productDetailSlidersSettings).mount();
});
