import Splide from '@splidejs/splide';

const technologySliders = document.querySelectorAll(".technology-section__row");

const technologySlidersSettings = {
  arrows: true,
  rewind: false,
  autoplay: false,
  perPage: 1,
  width: '100%',
  gap: '3em',
  perMove: 1,
  pagination: true,

};

technologySliders.forEach((slider) => {
  new Splide(slider, technologySlidersSettings).mount();
});
