const ktCookieStatementContainer = document.querySelector("#ktCookieStatementContainer");

if (ktCookieStatementContainer !== null) {

  const statementKey = "kt-cookie-statement-key";
  const statementSelector = "#ktCookieStatement";

  /**
   * Zkontroluje, zda existuje cookie (hodnota dle klíče)
   * @param  {string} cookieName
   */
  const checkCookieRecord = (cookieName) => {
    const cookieValue = getCookieRecord(cookieName);
    if (cookieValue != "") {
      return true;
    }
    return false;
  }

  /**
   * Vrátí hodnotu cookie dle klíče
   * @param  {string} cookieName
   */
  const getCookieRecord = (cookieName) => {
    const name = cookieName + "=";
    const cookies = document.cookie.split(";");

    cookies.forEach((cookie) => {

      while (cookie.charAt(0) == " ") {
        cookie = cookie.substring(1);
      }
      if (cookie.indexOf(name) == 0) {
        return cookie.substring(name.length, cookie.length);
      }
    });

    return "";
  }

  /**
   * Nastaví cookie hodnotu dle klíče po zadanou dobu (pro celou cestu /)
   * @param  {string} cookieName
   * @param  {string} cookieValue
   * @param  {string} expirationDaysCount
   */
  const setCookieRecord = (cookieName, cookieValue, expirationDaysCount) => {
    const date = new Date();
    date.setFullYear(date.getFullYear() + expirationDaysCount);
    document.cookie = cookieName + "=" + cookieValue + "; path=/; expires=" + date.toUTCString();
  }

  if (!checkCookieRecord(statementKey)) {
    document.querySelector(statementSelector).style.display = "flex";
  }

  const cookiesConsentButton = document.querySelector("#ktCookieStatementConfirm");
  if (cookiesConsentButton !== null) {
    cookiesConsentButton.addEventListener("click", () => {
      setCookieRecord(statementKey, 1, 10);
      document.querySelector(statementSelector).style.display = "none";
    });
  }

}
