const animation = () => {
  const animatedSections = document.querySelectorAll(".--animated")
  if (!animatedSections) {
    return
  }
  const vh = Math.max(document.documentElement.clientHeight || 0, window.innerHeight || 0);
  const hpHalf = vh / 2;
  animatedSections.forEach(section => {
    if ((section.classList.contains('signpost-section') && window.innerWidth < 992) || (section.classList.contains('about-us-section') && window.innerWidth < 576) || (section.classList.contains('contact-form-section') && window.innerWidth < 576) || (section.classList.contains('footer-main') && window.innerWidth < 576)) {
      return;
    }
    section.classList.remove("--animated");
  });
  window.onscroll = function () {
    animatedSections.forEach(section => {
      const sectionOffset = section.offsetTop;
      const pageOffset = window.pageYOffset;

      if ((pageOffset + hpHalf) >= sectionOffset) {
        section.classList.add("--animated");
      }


    });
  };
}





animation();
