const videoLazyload = () => {
  const videoSections = document.querySelectorAll(".video-section");

  if (!videoSections) {
    return;
  }

  videoSections.forEach(section => {
    const image = section.querySelector(".video-section__placeholder-img");
    if (!image) {
      return
    }
    const spinner = section.querySelector(".video-section__spinner");
    const playButton = section.querySelector(".video-section__play-button");
    const video = section.querySelector("iframe, video");
    const videoUrl = video.getAttribute('data-url');

    image.addEventListener('click', () => {
      video.src = videoUrl;
      video.classList.add("visible");
      image.classList.add("d-none");
      playButton.classList.add("d-none");
      spinner.classList.add("visible");
    });
  });
}

videoLazyload();
