import Splide from '@splidejs/splide';

const GalleriesSliders = document.querySelectorAll(".gallery-slider-section__row");

const GalleriesSlidersSettings = {
  arrows: true,
  rewind: false,
  autoplay: false,
  perPage: 2,
  width: '100%',
  perMove: 2,
  gap: '2em',
  pagination: true,
  breakpoints: {
    992: {
      gap: '1em',
    }
  }
};

GalleriesSliders.forEach((slider) => {
  new Splide(slider, GalleriesSlidersSettings).mount();
});
