const openPopup = () => {

  const button = document.querySelector(".--requestPopup,.--customPopup");
  if (!button) {
    return
  }
  button.addEventListener('click', (e) => {
    const target = e.target;
    if (target.classList.contains("--requestPopup")) {
      const popup = document.querySelector(".popup-form.--requestPopup")
      popup.classList.add("--visible")
    } else {
      if (target.classList.contains("--customPopup")) {
        const popup = document.querySelector(".popup-form.--customPopup")
        popup.classList.add("--visible")
      }
    }

  });
}

const closePopup = () => {

  document.addEventListener('click', (e) => {
    const target = e.target;
    const cross = document.querySelector(".popup-form__cross")
    const popup = document.querySelector(".popup-form")
    if (target === cross || target === popup) {
      if (popup.classList.contains("--visible")) {
        popup.classList.remove("--visible")
      }
    }
  });
}

openPopup();
closePopup();
